class Player {
  constructor(name) {
    this.name = name;
    this.level = 1;
    this.hp = 100;
    this.maxHp = 100;
    this.xp = 0;
    this.xpToLevel = 100;
  }

  gainXP(amount) {
    this.xp += amount;
    while (this.xp >= this.xpToLevel) {
      this.xp -= this.xpToLevel;
      this.level++;
      this.maxHp += 10;
      this.hp = this.maxHp;
      this.xpToLevel = Math.floor(this.xpToLevel * 1.5);
      // TODO: emit 'levelup' event with { name, level, maxHp }
    }
  }

  takeDamage(amount) {
    const actual = Math.min(amount, this.hp);
    this.hp -= actual;
    // TODO: emit 'damage' event with { name, amount: actual, hpRemaining: this.hp }
    if (this.hp <= 0) {
      // TODO: emit 'death' event with { name, level }
    }
    return actual;
  }

  heal(amount) {
    const actual = Math.min(amount, this.maxHp - this.hp);
    this.hp += actual;
    return actual;
  }
}

module.exports = { Player };

