const assert = require('assert');
let passed = 0, failed = 0;
function runTest(name, fn) { try { fn(); passed++; console.log('PASS: ' + name); } catch(e) { failed++; console.log('FAIL: ' + name + ' — ' + e.message); } }

// EventEmitter
runTest('emitter exists', () => { const { EventEmitter } = require('../events/emitter'); assert.ok(EventEmitter); });
runTest('emitter on/emit', () => { const { EventEmitter } = require('../events/emitter'); const e = new EventEmitter(); let called = false; e.on('test', () => { called = true; }); e.emit('test'); assert.ok(called); });
runTest('emitter passes data', () => { const { EventEmitter } = require('../events/emitter'); const e = new EventEmitter(); let data = null; e.on('test', (d) => { data = d; }); e.emit('test', { x: 1 }); assert.deepStrictEqual(data, { x: 1 }); });
runTest('emitter off removes listener', () => { const { EventEmitter } = require('../events/emitter'); const e = new EventEmitter(); let count = 0; const fn = () => { count++; }; e.on('test', fn); e.emit('test'); e.off('test', fn); e.emit('test'); assert.strictEqual(count, 1); });
runTest('emitter multiple listeners', () => { const { EventEmitter } = require('../events/emitter'); const e = new EventEmitter(); let a = 0, b = 0; e.on('test', () => a++); e.on('test', () => b++); e.emit('test'); assert.strictEqual(a, 1); assert.strictEqual(b, 1); });

// Logger
runTest('logger exists', () => { const { EventLogger } = require('../events/logger'); assert.ok(EventLogger); });
runTest('logger records events', () => { const { EventEmitter } = require('../events/emitter'); const { EventLogger } = require('../events/logger'); const e = new EventEmitter(); const log = new EventLogger(e); e.emit('test', { x: 1 }); const entries = log.getEntries(); assert.strictEqual(entries.length, 1); assert.strictEqual(entries[0].event, 'test'); assert.deepStrictEqual(entries[0].data, { x: 1 }); });
runTest('logger clear', () => { const { EventEmitter } = require('../events/emitter'); const { EventLogger } = require('../events/logger'); const e = new EventEmitter(); const log = new EventLogger(e); e.emit('a'); e.emit('b'); assert.strictEqual(log.getEntries().length, 2); log.clear(); assert.strictEqual(log.getEntries().length, 0); });

// Player events integration
runTest('player emits levelup', () => { const { createPlayer } = require('../events/index'); const { player, logger } = createPlayer('Hero'); player.gainXP(100); const events = logger.getEntries().filter(e => e.event === 'levelup'); assert.strictEqual(events.length, 1); assert.strictEqual(events[0].data.level, 2); });
runTest('player emits damage', () => { const { createPlayer } = require('../events/index'); const { player, logger } = createPlayer('Hero'); player.takeDamage(30); const events = logger.getEntries().filter(e => e.event === 'damage'); assert.strictEqual(events.length, 1); assert.strictEqual(events[0].data.amount, 30); assert.strictEqual(events[0].data.hpRemaining, 70); });
runTest('player emits death', () => { const { createPlayer } = require('../events/index'); const { player, logger } = createPlayer('Hero'); player.takeDamage(200); const events = logger.getEntries().filter(e => e.event === 'death'); assert.strictEqual(events.length, 1); });
runTest('player multi-levelup', () => { const { createPlayer } = require('../events/index'); const { player, logger } = createPlayer('Hero'); player.gainXP(300); const events = logger.getEntries().filter(e => e.event === 'levelup'); assert.ok(events.length >= 2, 'Should level up at least twice with 300 XP'); });

console.log('\n' + passed + '/' + (passed+failed) + ' tests passed');
if (failed > 0) process.exit(1);
